var apiKey = getVar('pexels_api_key');
if (!apiKey) return JSON.stringify({error: "Pexels API key not configured. Set the 'pexels_api_key' variable."});

var orientation = args.orientation || 'portrait';
var perPage = args.per_page || 5;
if (perPage < 1) perPage = 1;
if (perPage > 10) perPage = 10;
var size = args.size || 'large';

var url = 'https://api.pexels.com/v1/search?query=' + encodeURIComponent(args.query) + '&orientation=' + orientation + '&per_page=' + perPage + '&size=' + size;
if (args.color) {
  url += '&color=' + encodeURIComponent(args.color);
}

var resp = httpGet(url, {
  'Authorization': apiKey
});

if (resp.status !== 200) {
  var errBody = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
  return JSON.stringify({error: 'Pexels API error (HTTP ' + resp.status + '): ' + errBody});
}

var data = typeof resp.body === 'string' ? jsonParse(resp.body) : resp.body;

if (!data.photos || data.photos.length === 0) {
  return JSON.stringify({results: [], total: 0, query: args.query, note: 'No images found. Try broader search terms.'});
}

var results = [];
for (var i = 0; i < data.photos.length; i++) {
  var photo = data.photos[i];
  results.push({
    id: photo.id,
    url_original: photo.src.original,
    url_large2x: photo.src.large2x,
    url_large: photo.src.large,
    url_portrait: photo.src.portrait,
    url_landscape: photo.src.landscape,
    width: photo.width,
    height: photo.height,
    photographer: photo.photographer,
    alt: photo.alt || ''
  });
}

return JSON.stringify({
  results: results,
  total: data.total_results,
  query: args.query
}, null, 2);

var apiKey = getVar('pexels_api_key');
if (!apiKey) return JSON.stringify({error: "Pexels API key not configured. Set the 'pexels_api_key' variable."});

var orientation = args.orientation || 'portrait';
var perPage = args.per_page || 3;
if (perPage < 1) perPage = 1;
if (perPage > 10) perPage = 10;
var size = args.size || 'medium';

var url = 'https://api.pexels.com/videos/search?query=' + encodeURIComponent(args.query) + '&orientation=' + orientation + '&per_page=' + perPage + '&size=' + size;

var resp = httpGet(url, {
  'Authorization': apiKey
});

if (resp.status !== 200) {
  var errBody = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
  return JSON.stringify({error: 'Pexels API error (HTTP ' + resp.status + '): ' + errBody});
}

var data = typeof resp.body === 'string' ? jsonParse(resp.body) : resp.body;

if (!data.videos || data.videos.length === 0) {
  return JSON.stringify({results: [], total: 0, query: args.query, note: 'No videos found. Try broader search terms.'});
}

var results = [];
for (var i = 0; i < data.videos.length; i++) {
  var video = data.videos[i];
  var files = [];
  if (video.video_files) {
    for (var j = 0; j < video.video_files.length; j++) {
      var f = video.video_files[j];
      files.push({
        quality: f.quality,
        width: f.width,
        height: f.height,
        url: f.link,
        file_type: f.file_type
      });
    }
  }
  results.push({
    id: video.id,
    duration: video.duration,
    width: video.width,
    height: video.height,
    files: files
  });
}

return JSON.stringify({
  results: results,
  total: data.total_results,
  query: args.query
}, null, 2);
